def test_can_disable_none_as_delete_marker():
    defaults = {"retry": {"count": 3, "backoff": "linear"}, "region": "us"}
    override = {"retry": {"backoff": None}, "region": None}

    assert merge_policy(defaults, override) == {"retry": {"count": 3}}
