from solution import merge_policy


def test_merges_recursively_and_removes_none_values():
    defaults = {
        "retry": {"count": 3, "backoff": "linear"},
        "log": True,
        "region": "us",
    }
    override = {
        "retry": {"backoff": "expo"},
        "region": None,
    }

    result = merge_policy(defaults, override)

    assert result == {
        "retry": {"count": 3, "backoff": "expo"},
        "log": True,
    }
    assert defaults["retry"]["backoff"] == "linear"
    assert "region" in defaults
